import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Heart, Eye, EyeOff, ArrowLeft } from 'lucide-react';

export default function Login() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [showPw, setShowPw] = useState(false);
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const user = await login(form.email, form.password);
      toast.success(`Welcome back, ${user.name}!`);
      navigate(`/${user.role}-dashboard`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #f0fdfa 0%, #e0f2fe 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}>
      <div style={{ width: '100%', maxWidth: 440 }}>
        <div style={{ textAlign: 'center', marginBottom: 32 }}>
          <Link to="/" style={{ display: 'inline-flex', alignItems: 'center', gap: 8, color: '#0d9488', fontWeight: 600, fontSize: 14, marginBottom: 20 }}>
            <ArrowLeft size={16} /> Back to home
          </Link>
          <div style={{ width: 56, height: 56, borderRadius: 16, background: '#0d9488', display: 'flex', alignItems: 'center', justifyContent: 'center', margin: '0 auto 16px' }}>
            <Heart size={28} color="white" fill="white" />
          </div>
          <h1 style={{ fontSize: 30, fontFamily: 'DM Serif Display,serif', color: '#111827', marginBottom: 6 }}>Welcome back</h1>
          <p style={{ color: '#6b7280', fontSize: 15 }}>Sign in to your Prana Solutions account</p>
        </div>

        <div className="card" style={{ padding: 36 }}>
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Email address</label>
              <input className="form-input" type="email" placeholder="you@example.com" value={form.email}
                onChange={e => setForm({ ...form, email: e.target.value })} required />
            </div>
            <div className="form-group">
              <label className="form-label">Password</label>
              <div style={{ position: 'relative' }}>
                <input className="form-input" type={showPw ? 'text' : 'password'} placeholder="••••••••"
                  value={form.password} onChange={e => setForm({ ...form, password: e.target.value })} required
                  style={{ paddingRight: 44 }} />
                <button type="button" onClick={() => setShowPw(!showPw)}
                  style={{ position: 'absolute', right: 14, top: '50%', transform: 'translateY(-50%)', background: 'none', border: 'none', cursor: 'pointer', color: '#9ca3af' }}>
                  {showPw ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>

            <button className="btn btn-primary w-full" type="submit" disabled={loading} style={{ marginTop: 8 }}>
              {loading ? 'Signing in...' : 'Sign In'}
            </button>
          </form>

          <div style={{ textAlign: 'center', marginTop: 24, paddingTop: 20, borderTop: '1px solid #f3f4f6' }}>
            <p style={{ fontSize: 14, color: '#6b7280' }}>
              Don't have an account?{' '}
              <Link to="/signup" style={{ color: '#0d9488', fontWeight: 600 }}>Sign up free</Link>
            </p>
          </div>
        </div>

        {/* Demo credentials */}
        <div style={{ marginTop: 20, padding: 16, background: 'rgba(255,255,255,0.7)', borderRadius: 12, border: '1px dashed #99f6e4' }}>
          <p style={{ fontSize: 12, color: '#0f766e', fontWeight: 600, marginBottom: 8 }}>Demo Credentials:</p>
          <p style={{ fontSize: 12, color: '#374151' }}>User: user@demo.com / demo123</p>
          <p style={{ fontSize: 12, color: '#374151' }}>Caregiver: caregiver@demo.com / demo123</p>
        </div>
      </div>
    </div>
  );
}
